- Single integer → `[n]`
- Range `a-b` → inclusive array, ascending or descending based on comparison

Key edge case: negative numbers (e.g., `-1-5`, `1--5`, `-1--5`) mean simple `split('-')` won't work reliably. A regex cleanly handles all sign combinations.```
function parseRange(s) {
  var m = s.match(/^(-?\d+)-(-?\d+)$/);
  if (m) {
    var a = +m[1], b = +m[2], result = [];
    if (a <= b) {
      for (var i = a; i <= b; i++) result.push(i);
    } else {
      for (var i = a; i >= b; i--) result.push(i);
    }
    return result;
  }
  return [+s];
}
